def is_descended_from_northern_dancer(pedigree, horse_name):
    northern_dancer_ancestors = {'Northern Dancer'}
    if horse_name in pedigree:
        for ancestor in pedigree[horse_name]:
            if ancestor in northern_dancer_ancestors or is_descended_from_northern_dancer(pedigree, ancestor):
                return True
    return False

# Example usage:
pedigree = {
    'Big Truck': ['Hook and Ladder', 'Just A Ginny'],
    'Hook and Ladder': ['Northern Dancer', 'Another Mare']
}
print(is_descended_from_northern_dancer(pedigree, 'Big Truck'))  # Output: True
